2088	// resolveServerURL determines the base URL for the running DDx server.
2089	//
2090	// Resolution order (matches internal/serverreg):
2091	//  1. DDX_SERVER_URL environment variable (explicit override)
2092	//  2. ~/.local/share/ddx/server.addr (written by `ddx server` on startup)
2093	//  3. https://127.0.0.1:7743 (the canonical default — see FEAT-020)
2094	//
2095	// The addr file may record a bind-address URL like https://0.0.0.0:7743
2096	// (because the server binds to 0.0.0.0 for multi-interface access). Those
2097	// are valid listen addresses but not reachable as client targets on some
2098	// platforms — rewrite them to https://127.0.0.1:<port> for local clients.
2099	//
2100	// The probe-common-ports heuristic that used to live here only worked for
2101	// the legacy plaintext http://127.0.0.1:8080 setup and never honored the
2102	// TLS default that's been in place since alpha13. Clients that skipped
2103	// the addr file would silently get a connection refused and tell the
2104	// user the server wasn't running when it was listening on 7743.
2105	func resolveServerURL(projectRoot string) string {
2106		if u := os.Getenv("DDX_SERVER_URL"); u != "" {
2107			return u
2108		}
2109		if u := serverpkg.ReadServerAddr(); u != "" {
2110			return rewriteBindAddrForClient(u)
2111		}
2112		return "https://127.0.0.1:7743"
2113	}
2114	
2115	// rewriteBindAddrForClient converts a bind-address URL into a client-reachable
2116	// URL. 0.0.0.0 (and [::]) are valid listen addresses but not reachable as
2117	// client destinations on all platforms — substitute 127.0.0.1 so local HTTP
2118	// clients can always connect.
2119	func rewriteBindAddrForClient(u string) string {
2120		for _, bind := range []string{"//0.0.0.0:", "//[::]:", "//[::0]:"} {
2121			if idx := strings.Index(u, bind); idx >= 0 {
2122				return u[:idx] + "//127.0.0.1:" + u[idx+len(bind):]
2123			}
2124		}
2125		return u
2126	}
