636				if resolvedProvider != "" {
637					attemptProvider = resolvedProvider
638				}
639				attemptRcfg, _ := config.LoadAndResolve(projectRoot, config.CLIOverrides{
640					Harness:           resolvedHarness,
641					Model:             resolvedModel,
642					Provider:          attemptProvider,
643					ModelRef:          spec.ModelRef,
644					Effort:            spec.Effort,
645					OpaquePassthrough: spec.OpaquePassthrough,
646				})
647				res, err := agent.ExecuteBeadWithConfig(ctx, projectRoot, beadID, attemptRcfg, agent.ExecuteBeadRuntime{
648					BeadEvents: bead.NewStore(filepath.Join(projectRoot, ".ddx")),
649				}, gitOps)
650				if err != nil && res == nil {
651					return agent.ExecuteBeadReport{}, err
652				}
653				if res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 {
654					if landErr := evaluateGatesAndSubmit(projectRoot, res, gitOps, coordinator, landSafetyConfigFromConfig(projectRoot), log); landErr != nil && err == nil {
