// Package executeloop defines the canonical ExecuteLoopSpec used by every
// layer of the queue-drain dispatch path:
//
//	cobra RunE → ParseExecuteLoopSpec(cmd) (Spec, DispatchOptions)
//	             ↓
//	  (--local) runExecuteLoopInline(spec)
//	             ↓
//	  (default) httpSubmitExecuteLoop(spec) ── JSON ──▶ server.handleStartExecuteLoopWorker
//	                                              ↓ decode INTO THE SAME struct, then ApplyDefaults + Validate
//	                                          startExecuteLoop(spec)
//	                                              ↓ persist as spec.json — SAME struct, fully resolved
//	                                          runWorker(spec)
//
// One struct, JSON tags drive both wire format and disk persistence. Adding
// a new flag is (a) one struct field plus its JSON tag, and (b) one cobra
// binding in ParseExecuteLoopSpec. The wire/persistence path is structural —
// a field cannot be silently dropped because it round-trips through Marshal/
// Unmarshal and ends up in spec.json as well.
//
// Forward-compat: ddx is single-repo, single-version client/server today.
// SpecVersion is bumped if a wire-incompatible change ships; the server
// rejects payloads with SpecVersion > CurrentSpecVersion. Newer-server-
// older-client and same-version pairs always work because Unmarshal tolerates
// unknown fields by default. The same applies when loading legacy spec.json
// blobs from disk — older fields like min_tier/max_tier are silently ignored.
package executeloop

import (
	"encoding/json"
	"fmt"
	"strconv"
	"time"

	"github.com/spf13/cobra"

	"github.com/DocumentDrivenDX/ddx/internal/escalation"
)

// CurrentSpecVersion is the highest SpecVersion this build understands on
// the wire. Bumping this is a deliberate act — only do so when a wire-
// incompatible change ships.
const CurrentSpecVersion = 1

// ExecuteLoopSpec is the single canonical specification for an execute-loop
// run. It is the wire format between the CLI and the server, the on-disk
// spec.json under .ddx/workers/, and the in-process input to runWorker.
type ExecuteLoopSpec struct {
	SpecVersion int `json:"spec_version,omitempty"`

	ProjectRoot string `json:"project_root,omitempty"`

	Harness  string `json:"harness,omitempty"`
	Model    string `json:"model,omitempty"`
	Profile  string `json:"profile,omitempty"`
	Provider string `json:"provider,omitempty"`
	ModelRef string `json:"model_ref,omitempty"`
	Effort   string `json:"effort,omitempty"`

	// LabelFilter is a single-string filter passed through to the bead
	// queue scanner. Picker semantics (string vs []string) are owned by
	// ddx-9d55601f; keep this as string here.
	LabelFilter string `json:"label_filter,omitempty"`

	Once         bool          `json:"once,omitempty"`
	PollInterval time.Duration `json:"poll_interval,omitempty"`

	NoReview      bool   `json:"no_review,omitempty"`
	ReviewHarness string `json:"review_harness,omitempty"`
	ReviewModel   string `json:"review_model,omitempty"`

	// OpaquePassthrough, when true, skips DDx-side route validation and
	// config harness/model injection. Set by ddx work; not set by ddx
	// agent execute-loop.
	OpaquePassthrough bool `json:"opaque_passthrough,omitempty"`

	// MaxCostUSD caps accumulated billed cost. Zero means "unlimited" only
	// when explicitly set; ApplyDefaults fills in escalation.DefaultMaxCostUSD
	// when the field is left at the zero value.
	MaxCostUSD float64 `json:"max_cost_usd,omitempty"`

	// RequestTimeout is the per-request provider wall-clock timeout. Zero
	// leaves the upstream default in place.
	RequestTimeout time.Duration `json:"request_timeout,omitempty"`

	// MinPower / MaxPower are passthrough power bounds for the upstream
	// agent's routing. Zero means unconstrained.
	MinPower int `json:"min_power,omitempty"`
	MaxPower int `json:"max_power,omitempty"`

	// FromRev is the base git revision to start from (default: HEAD).
	FromRev string `json:"from_rev,omitempty"`
}

// DispatchOptions carries control-plane flags that govern how the CLI
// invocation is routed. They MUST NOT appear on ExecuteLoopSpec or be
// persisted to spec.json — they only describe how the operator invoked
// the binary, not the work to be done.
type DispatchOptions struct {
	Local bool
	JSON  bool
}

// MarshalJSON renders durations as operator-readable strings ("30s", "5m")
// so that spec.json blobs and HTTP request bodies are inspectable.
func (s ExecuteLoopSpec) MarshalJSON() ([]byte, error) {
	type alias ExecuteLoopSpec
	wire := struct {
		alias
		PollInterval   string `json:"poll_interval,omitempty"`
		RequestTimeout string `json:"request_timeout,omitempty"`
	}{alias: alias(s)}
	if s.PollInterval > 0 {
		wire.PollInterval = s.PollInterval.String()
	}
	if s.RequestTimeout > 0 {
		wire.RequestTimeout = s.RequestTimeout.String()
	}
	return json.Marshal(wire)
}

// UnmarshalJSON tolerates both the canonical string form ("30s") and the
// legacy nanoseconds-as-number form for poll_interval / request_timeout.
// Unknown fields (e.g. legacy min_tier / max_tier) are silently ignored —
// this is what allows newer-server-older-client and old-on-disk spec.json
// files to load cleanly.
func (s *ExecuteLoopSpec) UnmarshalJSON(data []byte) error {
	type alias ExecuteLoopSpec
	wire := struct {
		*alias
		PollInterval   json.RawMessage `json:"poll_interval,omitempty"`
		RequestTimeout json.RawMessage `json:"request_timeout,omitempty"`
	}{alias: (*alias)(s)}
	if err := json.Unmarshal(data, &wire); err != nil {
		return err
	}
	d, err := decodeDurationField(wire.PollInterval, "poll_interval")
	if err != nil {
		return err
	}
	s.PollInterval = d
	d, err = decodeDurationField(wire.RequestTimeout, "request_timeout")
	if err != nil {
		return err
	}
	s.RequestTimeout = d
	return nil
}

func decodeDurationField(raw json.RawMessage, name string) (time.Duration, error) {
	if len(raw) == 0 || string(raw) == "null" {
		return 0, nil
	}
	// String form: "30s"
	if raw[0] == '"' {
		var str string
		if err := json.Unmarshal(raw, &str); err != nil {
			return 0, fmt.Errorf("decode %s: %w", name, err)
		}
		if str == "" {
			return 0, nil
		}
		d, err := time.ParseDuration(str)
		if err != nil {
			return 0, fmt.Errorf("invalid %s: %w", name, err)
		}
		return d, nil
	}
	// Numeric form: nanoseconds (legacy time.Duration default)
	n, err := strconv.ParseInt(string(raw), 10, 64)
	if err != nil {
		return 0, fmt.Errorf("invalid %s: %w", name, err)
	}
	return time.Duration(n), nil
}

// ApplyDefaults fills in fields that have well-known fallbacks. It is
// idempotent — calling it twice produces the same result.
//
// Lifecycle: cobra binding sets the operator-supplied defaults; the server
// calls ApplyDefaults after decoding so the persisted spec.json is fully
// resolved and runWorker does not need to reach for any other source of
// truth at runtime.
func (s *ExecuteLoopSpec) ApplyDefaults() {
	if s.SpecVersion == 0 {
		s.SpecVersion = CurrentSpecVersion
	}
	if s.Profile == "" {
		s.Profile = "default"
	}
	// 30s keeps server-managed workers alive across empty polls
	// (ddx-dc157075). Operators wanting drain-and-exit semantics pass
	// --once or an explicit poll_interval=0; we cannot distinguish "0"
	// from "unset" here, so the cobra binding is the source of truth
	// for the operator's intent and ApplyDefaults only fires when
	// PollInterval is exactly the zero value (nothing was set).
	if s.PollInterval == 0 && !s.Once {
		s.PollInterval = 30 * time.Second
	}
	if s.MaxCostUSD == 0 {
		s.MaxCostUSD = escalation.DefaultMaxCostUSD
	}
}

// Validate returns an error when the spec is structurally invalid. It is
// safe to call before or after ApplyDefaults.
func (s ExecuteLoopSpec) Validate() error {
	if s.SpecVersion > CurrentSpecVersion {
		return &UnsupportedSpecVersionError{
			Got:       s.SpecVersion,
			Supported: CurrentSpecVersion,
		}
	}
	if s.PollInterval < 0 {
		return fmt.Errorf("poll_interval must be >= 0")
	}
	if s.RequestTimeout < 0 {
		return fmt.Errorf("request_timeout must be >= 0")
	}
	if s.MinPower < 0 || s.MaxPower < 0 {
		return fmt.Errorf("min_power/max_power must be >= 0")
	}
	if s.MinPower > 0 && s.MaxPower > 0 && s.MinPower > s.MaxPower {
		return fmt.Errorf("min_power (%d) must be <= max_power (%d)", s.MinPower, s.MaxPower)
	}
	return nil
}

// UnsupportedSpecVersionError is returned by Validate when the spec uses a
// SpecVersion newer than this build understands. The server returns it as
// a 400 with a capability list in the body.
type UnsupportedSpecVersionError struct {
	Got       int
	Supported int
}

func (e *UnsupportedSpecVersionError) Error() string {
	return fmt.Sprintf("unsupported spec_version %d (this build supports up to %d)", e.Got, e.Supported)
}

// ParseExecuteLoopSpec is the single cobra→spec conversion. It is called
// only from the cobra RunE for `ddx work` and `ddx agent execute-loop`.
// Both commands declare the same flag set (see RegisterFlags below) so the
// spec they produce is identical except for OpaquePassthrough (set true by
// ddx work, false by ddx agent execute-loop).
func ParseExecuteLoopSpec(cmd *cobra.Command, opaquePassthrough bool) (ExecuteLoopSpec, DispatchOptions, error) {
	spec := ExecuteLoopSpec{
		SpecVersion:       CurrentSpecVersion,
		OpaquePassthrough: opaquePassthrough,
	}
	get := func(name string, into any) {
		f := cmd.Flags().Lookup(name)
		if f == nil {
			return
		}
		switch v := into.(type) {
		case *string:
			*v, _ = cmd.Flags().GetString(name)
		case *bool:
			*v, _ = cmd.Flags().GetBool(name)
		case *time.Duration:
			*v, _ = cmd.Flags().GetDuration(name)
		case *float64:
			*v, _ = cmd.Flags().GetFloat64(name)
		case *int:
			*v, _ = cmd.Flags().GetInt(name)
		}
	}
	get("harness", &spec.Harness)
	get("model", &spec.Model)
	get("profile", &spec.Profile)
	get("provider", &spec.Provider)
	get("model-ref", &spec.ModelRef)
	get("effort", &spec.Effort)
	get("once", &spec.Once)
	get("poll-interval", &spec.PollInterval)
	get("no-review", &spec.NoReview)
	get("review-harness", &spec.ReviewHarness)
	get("review-model", &spec.ReviewModel)
	get("max-cost", &spec.MaxCostUSD)
	get("request-timeout", &spec.RequestTimeout)
	get("min-power", &spec.MinPower)
	get("max-power", &spec.MaxPower)
	get("from", &spec.FromRev)
	get("label-filter", &spec.LabelFilter)

	var dispatch DispatchOptions
	get("local", &dispatch.Local)
	get("json", &dispatch.JSON)

	return spec, dispatch, nil
}

