func (s *Server) handleStartExecuteLoopWorker(w http.ResponseWriter, r *http.Request) {
	if !isTrusted(r) {
		writeJSON(w, http.StatusForbidden, map[string]string{"error": "dispatch endpoints are localhost-only"})
		return
	}
	// Decode directly into the canonical ExecuteLoopSpec — no parallel
	// request struct (ddx-29058e2a). The spec's UnmarshalJSON tolerates
	// both string and numeric duration encodings and silently ignores
	// unknown fields (e.g. legacy min_tier / max_tier from older clients).
	var spec ExecuteLoopWorkerSpec
	if err := json.NewDecoder(r.Body).Decode(&spec); err != nil {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "invalid request body: " + err.Error()})
		return
	}

	// Resolve project_root: if provided, validate it against registered projects.
	// An empty project_root means "use the server's primary project" (default).
	if spec.ProjectRoot != "" {
		resolved := s.resolveRequestedProject(spec.ProjectRoot)
		if resolved == "" {
			writeJSON(w, http.StatusUnprocessableEntity, map[string]string{
				"error": fmt.Sprintf("no registered project matches %q; ensure the server was started from or has registered that project root", spec.ProjectRoot),
			})
			return
		}
		spec.ProjectRoot = resolved
	}

	// Server cannot trust the wire — apply defaults and validate before
	// passing the spec into StartExecuteLoop.
	spec.ApplyDefaults()
	if err := spec.Validate(); err != nil {
		var unsupp *executeloop.UnsupportedSpecVersionError
		if errors.As(err, &unsupp) {
			writeJSON(w, http.StatusBadRequest, map[string]any{
				"error":             unsupp.Error(),
				"supported_version": unsupp.Supported,
			})
			return
		}
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": err.Error()})
		return
	}

	record, err := s.workers.StartExecuteLoop(spec)
	if err != nil {
		writeJSON(w, http.StatusInternalServerError, map[string]string{"error": err.Error()})
		return
	}
	writeJSON(w, http.StatusCreated, record)
}
